INSERT [dbo].[Accommodations] ([Id], [DistrictId], [Name], [Address], [Description], [AverageRating], [StarRating], [PropertyTypeId], [Slug], [Status], [IsFeatured], [Latitude], [Longitude], [ViewCount], [CreatedAt], [UpdatedAt], [AiIndexStatus], [AiLastIndexedAt], [AiIndexError]) VALUES (4, 32, N'Salinda Resort Phu Quoc Island', N'Ấp Cửa Lấp, Xã Dương Tơ, TP. Phú Quốc', N'Khu nghỉ dưỡng 5 sao ven biển tuyệt đẹp tại Phú Quốc. Nổi tiếng với dịch vụ Spa đẳng cấp, hồ bơi lớn và bữa sáng buffet chuẩn quốc tế. Cực kỳ thích hợp cho gia đình có trẻ nhỏ.', 4.7, NULL, NULL, NULL, N'Active', 0, NULL, NULL, 0, CAST(N'2026-05-09T06:52:38.340' AS DateTime), NULL, N'Indexed', CAST(N'2026-05-09T11:04:07.197' AS DateTime), NULL)
GO
INSERT [dbo].[Accommodations] ([Id], [DistrictId], [Name], [Address], [Description], [AverageRating], [StarRating], [PropertyTypeId], [Slug], [Status], [IsFeatured], [Latitude], [Longitude], [ViewCount], [CreatedAt], [UpdatedAt], [AiIndexStatus], [AiLastIndexedAt], [AiIndexError]) VALUES (5, 36, N'Topas Ecolodge', N'Thanh Kim, Sa Pa', N'Khu nghỉ dưỡng sinh thái nằm trên đỉnh đồi tại Sapa. Sở hữu hồ bơi vô cực nhìn thẳng xuống thung lũng Mường Hoa. Rất yên tĩnh, phù hợp cho người yêu thiên nhiên, không có wifi trong phòng để đảm bảo sự tách biệt.', 4.8, NULL, NULL, NULL, N'Active', 0, NULL, NULL, 0, CAST(N'2026-05-09T06:52:38.340' AS DateTime), NULL, N'Indexed', CAST(N'2026-05-09T11:04:07.250' AS DateTime), NULL)
GO
INSERT [dbo].[Accommodations] ([Id], [DistrictId], [Name], [Address], [Description], [AverageRating], [StarRating], [PropertyTypeId], [Slug], [Status], [IsFeatured], [Latitude], [Longitude], [ViewCount], [CreatedAt], [UpdatedAt], [AiIndexStatus], [AiLastIndexedAt], [AiIndexError]) VALUES (6, 24, N'Melia Hanoi', N'44B Lý Thường Kiệt, Quận Hoàn Kiếm', N'Khách sạn 5 sao nằm ngay trung tâm thủ đô Hà Nội, cách Hồ Gươm chỉ vài phút đi bộ. Dịch vụ chuyên nghiệp, phòng ốc hiện đại, phù hợp cho cả khách du lịch và khách đi công tác.', 4.5, NULL, NULL, NULL, N'Active', 0, NULL, NULL, 0, CAST(N'2026-05-09T06:52:38.340' AS DateTime), NULL, N'Indexed', CAST(N'2026-05-09T11:04:07.283' AS DateTime), NULL)
GO
