INSERT [dbo].[RagChunks] ([Id], [DocumentId], [ChunkIndex], [Content], [EmbeddingJson], [EmbeddingModel], [TokenCount], [CreatedAt]) VALUES (3, 4, 0, N'Tên nơi lưu trú: Topas Ecolodge

Địa chỉ: Thanh Kim, Sa Pa

Quận/Huyện: Lào Cai

Loại lưu trú: 

Mô tả: Khu nghỉ dưỡng sinh thái nằm trên đỉnh đồi tại Sapa. Sở hữu hồ bơi vô cực nhìn thẳng xuống thung lũng Mường Hoa. Rất yên tĩnh, phù hợp cho người yêu thiên nhiên, không có wifi trong phòng để đảm bảo sự tách biệt.

Tọa độ: , 

Danh sách phòng:

- Phòng: Premium Bungalow

  Giá mỗi đêm: 4,500,000đ

  Sức chứa tổng: 2 người

  Người lớn: 2, Trẻ em: 0

  Tổng số phòng: 12

  Diện tích:  m2

  Loại giường: 

  Mô tả phòng: Bungalow nằm ven đồi, view thung lũng ruộng bậc thang.

- Phòng: Suite Bungalow

  Giá mỗi đêm: 6,500,000đ

  Sức chứa tổng: 2 người

  Người lớn: 2, Trẻ em: 0

  Tổng số phòng: 5

  Diện tích:  m2

  Loại giường: 

  Mô tả phòng: Bungalow diện tích lớn, gần hồ bơi vô cực nhất.

